VALUES
  ('optometrist-moex-01984', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何者是典型的軟式隱形眼鏡鏡片「鬆配適」（loosesoftlensfit）的表現？', '["視力不穩定", "眨眼後顯示大約0.3mm的鏡片移動，及同向性轉向（version）時有類似的延遲（lag）量", "鏡片邊緣與鞏膜對齊但不壓迫結膜", "鏡片中心定位且覆蓋輪部至少1mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01985', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '對於硬式透氣隱形眼鏡（rigidgas-permeablelens）往下偏（inferiordecentration）的處理方式，下列何者較 不適宜？', '["對於近視的人，建議基弧改陡一點（steeper）", "建議隱形眼鏡的厚度改薄一點", "可考慮改用lenticulardesign的硬式隱形眼鏡", "可考慮改用scleraldesign的硬式隱形眼鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01986', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜弧度儀測量，下列何者錯誤？', '["角膜弧度測量儀是以兩條互為垂直的經線，所測出中心3mm處角膜的平均弧度", "角膜弧度測量儀，可能看出角膜表面的不平整", "角膜弧度為 43.50@180°/43.50@90°，表示電腦驗光時沒有散光", "角膜散光是指兩個經線的屈率不同，42.00D@90°/44.00D@180°為逆性散光"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01987', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關細隙燈生體顯微鏡（slitlampbiomicroscopy）的檢查，下列敘述何者錯誤？', '["鏡片配戴與角膜的關係，可以寬光束，低強度白光、低倍數來掃描觀察鏡片表面", "可觀察淚液的品質，下眼瞼淚湖（lacrimallake）的高度，小於0.1mm為淚液不足", "以間接背面反射照射法（indirectretroillumination），可看到角膜上皮水腫", "可看出硬式隱形眼鏡造成的眼鏡性視力模糊（spectacleblur）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01988', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '隱形眼鏡所引起的角膜變形（warpage），下列敘述何者錯誤？', '["主要是因為角膜上皮的變化", "PMMA鏡片比日戴型透氧硬式隱形眼鏡易造成角膜變形", "也會發生在水膠軟式隱形眼鏡", "愈厚的鏡片愈容易造成角膜變形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01989', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於角膜黴菌感染和隱形眼鏡，下列敘述何者錯誤？', '["角膜黴菌感染的危險因子為受傷、使用隱形眼鏡時間過長、隱形眼鏡照顧或清潔不周和糖尿病病患", "角膜黴菌感染在美國最常見的是麴菌（aspergillus），在全世界最常見的則是鐮孢菌（fusarium）", "病灶常有羽毛狀邊緣的基質浸潤（stromalinfiltrationwithfeatheryborders）", "比起細菌性的感染，病程通常較長且難治"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01990', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴軟式隱形眼鏡引起的併發症基質層（stromal）有褶痕（folds）之敘述，下列何者最正確？', '["常見於使用矽水膠（siliconehydrogels）的鏡片配戴者", "有條紋（striate）的基質層約有9% 水腫（edema），而有褶痕的基質層約有5% 水腫", "褶痕常出現在基質層的前表層", "常見於配戴遠視鏡片或中心較厚的軟式水膠隱形眼鏡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01991', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '角膜上方弓形表皮破損（superior epithelialarcuatelesions）為戴隱形眼鏡者在角膜上緣近輪部處產生一弧 形的表皮破損，有關其敘述下列何者正確？', '["和微生物感染有關", "和鏡片的機械性摩擦有關", "硬式鏡片材質較硬，因此比軟式容易發生", "水膠鏡片透氧度較低，因此比矽水膠鏡片容易發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01992', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '改善三點和九點角膜染色（3and9o''clockcornealstaining）之方法，下列何者較無效？', '["眨眼練習", "降低鏡片周邊厚度", "增加周邊翹角", "加大鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01993', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴隱形眼鏡導致的巨大乳突結膜炎（giantpapillaryconjunctivitis），下列敘述何者錯誤？', '["可用拋棄式隱形眼鏡（disposablelens）來預防", "隱形眼鏡取出後立即用清潔液搓洗可降低其發生機會", "可用抗組織胺／肥胖細胞穩定藥物（antihistamine/mastcellstabilizer）治療", "配戴矽水膠材質隱形眼鏡不會導致其發生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
